/** Resolves a Lucide icon by its kebab-case or camelCase name. Falls back to [Lucide.Tag]. */
fun Lucide.byString(iconName: String?): ImageVector {
    val key = iconName
        .orEmpty()
        .trim()
        .lowercase()
        .replace(Regex("[_\\- ]"), "")
    return iconMap[key] ?: Lucide.Tag
}

